export default function App() {
  const requestSeqRef = useRef(0);
  const [query, setQuery] = useState('');
  const [status, setStatus] = useState<Status>('idle');
  const [isOpen, setIsOpen] = useState(false);
  const [activeIndex, setActiveIndex] = useState(-1);
  const [results, setResults] = useState<string[]>([]);

  function handleInputChange(value: string): void {
    requestSeqRef.current += 1;
    setQuery(value);
    setResults([]);
    setActiveIndex(-1);
    setStatus(value.trim() ? 'loading' : 'idle');
    setIsOpen(Boolean(value.trim()));
  }

  useEffect(() => {
    const trimmed = query.trim();
    if (!trimmed) return;
    let ignore = false;
    const controller = new AbortController();
    const requestId = ++requestSeqRef.current;
    setResults([]);
    setStatus('loading');

    const debounceId = window.setTimeout(async () => {
      try {
        const nextResults = await searchCities(trimmed, controller.signal);
        if (ignore || controller.signal.aborted || requestSeqRef.current !== requestId) return;
        setResults(nextResults);
        setStatus(nextResults.length ? 'success' : 'empty');
      } catch (error) {
        if (ignore || controller.signal.aborted || requestSeqRef.current !== requestId) return;
        setResults([]);
        setStatus('error');
      }
    }, 300);

    return () => {
      ignore = true;
      controller.abort();
      window.clearTimeout(debounceId);
    };
  }, [query]);

  function handleKeyDown(event: React.KeyboardEvent<HTMLInputElement>) {
    if (status === 'loading') return;
    if (event.key === 'Enter' && status === 'success' && activeIndex >= 0) {
      selectOption(results[activeIndex]);
    }
  }

  return (
    <>
      <label id="autocomplete-label" htmlFor="autocomplete-query">Search cities</label>
      <input
        id="autocomplete-query"
        role="combobox"
        aria-labelledby="autocomplete-label"
        aria-expanded={isOpen}
        aria-controls="autocomplete-listbox"
        value={query}
        onChange={(event) => handleInputChange(event.target.value)}
        onKeyDown={handleKeyDown}
      />
      {status === 'success' && results.map((item) => (
        <div key={item} role="option" onPointerDown={() => selectOption(item)}>{item}</div>
      ))}
    </>
  );
}
